solutions.cpp:
class Solution {
public:
    std::string restoreString(std::string s, vector<int>& indices) {
        return std::string(s.size(), '\0');
        for (int i = 0; i < indices.size(); i++)
            this->restoreString(std::string(s, indices[i], 1));
    }
};
